declare class LWGSDK {
  /**
   * Get the server time
   * @param param  success: success callback |  fail: fail callback
   */
  public static getServeTime(param: { success: Function; fail: Function }): void;


  public static init(param: { chn: string; debug: boolean; host: string; debugHost: string; resourceHost: string; success: Function, fail: Function }): void;

  /**
   *  Tutorial
   * @param param guide_id: guide step id, reporting means the step is completed (showing does not mean completed) |  success callback |  fail callback
   */
  public static reportUserGuide(param: { guideID: number; success: Function; fail: Function }): void;


  public static updateArchiveInfo(option: { archive: any; version: number; useClientVersion: boolean; success: Function, fail: Function}): void;


  public static request(option: { url: string; data: any; method: string; crypto: boolean; success: Function; fail: Function }): void
  /**
   *  Skip the tutorial
   * @param param guide_id: the guide step id when skipping, reporting means the step is completed (showing does not mean completed) |  success callback | fail callback
   */
  public static reportSkipGuide(param: { guideID: number; success: Function; fail: Function }): void;

  /**
   * Enter a Level
   * @param param stage: Level | success callback | fail callback
   */
  public static reportEnterStage(param: { stage: number; success: Function; fail: Function }): void;

  /**
   * End-of-Level event
   * @param param stage: Level |  status: 1-success 0-fail | continueTimes: continue (revive) count |  operateTimes: core operation count, e.g. for parking it's the parking count, for mowing it's the mow operation count |
   * costTime: total elapsed time in seconds | success: success callback | fail: fail callback
   */

  public static reportEndStage(param: { stage: number; status: number; continueTimes: number; operateTimes: number; costTime: number; success: Function; fail: Function }): void;

  /**
   * Loading-time stats: record start
   */
  public static recordLoadingTimeStart(): void;

  /**
   * Loading-time stats: record end
   * @param param isFirstLoad: whether it's the first load, true if so otherwise false |  result: result, 0 = normal; non-0 = load failed, see LWGSDK.LOAD_ERROR_CODE for the specific error code |  success callback | fail callback
   */
  public static recordLoadingTimeEnd(param: { isFirstLoad: boolean; result: number; success: Function; fail: Function }): void;

  /**
   * Generic time-cost stats reporting API: record start
   * @param param the behavior key
   */
  public static recordTimeCostStart(action: string): void;

  /**
   * Generic time-cost stats reporting API: record end
   * @param param  action: the event behavior, must be aligned with the server | result: result, 0 = normal; non-0 = load failed | success callback | fail callback
   */
  public static recordTimeCostEnd(param: { action: string; result: number; success: Function; fail: Function }): void;



  /**
   * Rewarded video
   * @param param loc: ad slot | ad_platform: the client's current display platform | ext: other data, optional | success: success callback | fail: fail callback
   */
  public static showRewardVideo(param: { loc: string; success: Function; fail: Function }): void;


  public static showInteraction(param: { loc: string; success: Function, fail: Function}): void;

}
